function l(){const o=document.querySelectorAll('input[type="file"][name="wheel_photos[]"]');o.length&&o.forEach(e=>{const t=e.closest("form")?.querySelector(".file-list");t&&e.addEventListener("change",()=>{t.innerHTML="",e.files.length&&Array.from(e.files).forEach(i=>{const n=document.createElement("div");n.className="file-item";const r=Math.round(i.size/1024);n.textContent=`${i.name} (${r} KB)`,t.appendChild(n)})})})}export{l as initUploadPhotos};
